"""
legion_embedded_assets.py — Daemon + installer source baked into Python.

Why this exists (iter 322fh):
  Production deploy bundle was silently dropping the /app/backend/legion_assets/
  directory, so /api/legion/install and /api/legion/daemon-source returned 503
  on aurem.live even after the iter 322fg fix. Embedding the bytes (base64)
  inside a regular .py module guarantees they ship with the rest of the
  backend code — no directory walk, no Cloud Build filter weirdness.

  Canonical sources still live at:
      /app/aurem-cto/daemon/legion_daemon.py
      /app/aurem-cto/daemon/install.sh

  The mirror at /app/backend/legion_assets/ is also still maintained.
  This file is regenerated by /app/scripts/sync_legion_embed.py — see footer.
"""
from __future__ import annotations

import base64
from pathlib import Path

_CANONICAL_DAEMON  = Path("/app/aurem-cto/daemon/legion_daemon.py")
_CANONICAL_INSTALL = Path("/app/aurem-cto/daemon/install.sh")
_MIRROR_DAEMON     = Path(__file__).parent / "legion_assets" / "legion_daemon.py"
_MIRROR_INSTALL    = Path(__file__).parent / "legion_assets" / "install.sh"


def _decode(b64: str) -> str:
    return base64.b64decode(b64.encode("ascii")).decode("utf-8")


def get_daemon_source() -> str:
    """Prefer on-disk canonical → backend mirror → embedded constant."""
    for p in (_CANONICAL_DAEMON, _MIRROR_DAEMON):
        try:
            if p.is_file():
                return p.read_text()
        except Exception:
            continue
    return _decode(DAEMON_B64)


def get_install_script() -> str:
    for p in (_CANONICAL_INSTALL, _MIRROR_INSTALL):
        try:
            if p.is_file():
                return p.read_text()
        except Exception:
            continue
    return _decode(INSTALL_B64)


# ── Embedded base64 constants (regenerate via scripts/sync_legion_embed.py) ──
DAEMON_B64 = ""
INSTALL_B64 = ""
